function money(value?: number | null) {
  if (value == null) return "-";
  return `${new Intl.NumberFormat("sv-SE", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(Number(value)).replace(/\u00a0/g, " ")} kr`;
}

function fmtDate(date?: string | null) {
  if (!date) return "-";
  return String(date).slice(0, 10);
}

function fmtTime(time?: string | null) {
  if (!time) return "-";
  return String(time).slice(0, 5);
}

function fmtDateTime(value?: string | null) {
  if (!value) return "-";

  const d = new Date(value);
  if (Number.isNaN(d.getTime())) return String(value);

  return new Intl.DateTimeFormat("sv-SE", {
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
  })
    .format(d)
    .replace(",", "");
}

function paymentLabel(status?: string | null) {
  switch (status) {
    case "paid":
    case "completed":
    case "succeeded":
      return "Betalning godk\u00e4nd";
    case "pending":
    case "pending_payment":
      return "Inv\u00e4ntar betalning";
    case "unpaid":
      return "Obetald";
    case "failed":
      return "Betalning misslyckades";
    default:
      return status || "Ok\u00e4nd";
  }
}

function passengerName(passengers: Passenger[], fallback?: string | null) {
  if (!passengers.length) return cleanText(fallback || "-");

  const first = passengers[0];
  const name = cleanText(`${first.first_name || ""} ${first.last_name || ""}`.trim());

  if (!name || name === "-") return cleanText(fallback || "-");
  if (passengers.length === 1) return name;

  return `${name} + ${passengers.length - 1} till`;
}

function ticketTypeLabel(passengers: Passenger[], count?: number | null) {
  if (!passengers.length) return `${count || 1} Vuxen`;

  const grouped = passengers.reduce<Record<string, number>>((acc, passenger) => {
    const type = cleanText(passenger.passenger_type || "Vuxen");
    acc[type] = (acc[type] || 0) + 1;
    return acc;
  }, {});

  return Object.entries(grouped)
    .map(([type, amount]) => `${amount} ${type}`)
    .join(", ");
}

function seatSummary(passengers: Passenger[]) {
  const seats = passengers
    .map((passenger) => cleanText(passenger.seat_number || ""))
    .filter(Boolean)
    .map((seat) => {
      const lower = seat.toLowerCase();

      if (lower.includes("automat")) return "Ej valt";
      if (lower.includes("till")) return "Ej valt";
      if (seat.length > 8) return "Ej valt";

      return seat;
    });

  if (!seats.length) return "Ej valt";

  const unique = Array.from(new Set(seats));

  if (unique.length === 1) return unique[0];
  if (unique.length > 2) return `${unique.length} s\u00e4ten`;

  return unique.join(", ");
}

function vatIncluded(total?: number | null) {
  if (total == null) return null;
  const value = Number(total);
  return value - value / 1.06;
}

function roundedRectPath(width: number, height: number, radius: number) {
  const r = Math.min(radius, width / 2, height / 2);
  const c = r * 0.5522847498;

  return [
    `M ${r} 0`,
    `L ${width - r} 0`,
    `C ${width - r + c} 0 ${width} ${r - c} ${width} ${r}`,
    `L ${width} ${height - r}`,
    `C ${width} ${height - r + c} ${width - r + c} ${height} ${width - r} ${height}`,
    `L ${r} ${height}`,
    `C ${r - c} ${height} 0 ${height - r + c} 0 ${height - r}`,
    `L 0 ${r}`,
    `C 0 ${r - c} ${r - c} 0 ${r} 0`,
    "Z",
  ].join(" ");
}

function roundRect(
  page: PDFPage,
  x: number,
  y: number,
  w: number,
  h: number,
  r: number,
  options: {
    color?: RGB;
    borderColor?: RGB;
    borderWidth?: number;
  }
) {
  page.drawSvgPath(roundedRectPath(w, h, r), {
    x,
    y: y + h,
    color: options.color,
    borderColor: options.borderColor,
    borderWidth: options.borderWidth,
  });
}

function card(page: PDFPage, x: number, y: number, w: number, h: number, fill = C.white) {
  roundRect(page, x, y, w, h, 8, {
    color: fill,
    borderColor: C.border,
    borderWidth: 1,
  });
}

function fitText(value: string, font: PDFFont, size: number, maxWidth: number) {
  const text = cleanText(value);

  if (font.widthOfTextAtSize(text, size) <= maxWidth) return text;

  let out = text;

  while (out.length > 3 && font.widthOfTextAtSize(`${out}...`, size) > maxWidth) {
    out = out.slice(0, -1);
  }

  return `${out}...`;
}

function fitFontSize(value: string, font: PDFFont, startSize: number, minSize: number, maxWidth: number) {
  let size = startSize;
  const text = cleanText(value);

  while (size > minSize && font.widthOfTextAtSize(text, size) > maxWidth) {
    size -= 1;
  }

  return size;
}

function drawText(
  page: PDFPage,
  value: string,
  x: number,
  y: number,
  size: number,
  font: PDFFont,
  color: RGB,
  maxWidth?: number
) {
  const finalText = maxWidth ? fitText(value, font, size, maxWidth) : cleanText(value);

  page.drawText(finalText, {
    x,
    y,
    size,
    font,
    color,
  });
}

function drawCenter(
  page: PDFPage,
  value: string,
  x: number,
  y: number,
  w: number,
  size: number,
  font: PDFFont,
  color: RGB
) {
  const text = cleanText(value);
  const textWidth = font.widthOfTextAtSize(text, size);

  page.drawText(text, {
    x: x + (w - textWidth) / 2,
    y,
    size,
    font,
    color,
  });
}

function drawRight(
  page: PDFPage,
  value: string,
  rightX: number,
  y: number,
  size: number,
  font: PDFFont,
  color: RGB
) {
  const text = cleanText(value);
  const textWidth = font.widthOfTextAtSize(text, size);

  page.drawText(text, {
    x: rightX - textWidth,
    y,
    size,
    font,
    color,
  });
}

function line(page: PDFPage, x1: number, y1: number, x2: number, y2: number, color: RGB, width = 1) {
  page.drawLine({
    start: { x: x1, y: y1 },
    end: { x: x2, y: y2 },
    thickness: width,
    color,
  });
}

function circle(page: PDFPage, x: number, y: number, size: number, color?: RGB, borderColor?: RGB, borderWidth = 1) {
  page.drawCircle({
    x,
    y,
    size,
    color,
    borderColor,
    borderWidth: borderColor ? borderWidth : undefined,
  });
}

function icon(page: PDFPage, x: number, y: number, type: string) {
  const s = C.teal;

  if (type === "calendar") {
    page.drawRectangle({ x: x + 2, y: y + 2, width: 16, height: 15, borderColor: s, borderWidth: 1.2 });
    line(page, x + 2, y + 13, x + 18, y + 13, s, 1.2);
    line(page, x + 6, y + 18, x + 6, y + 15, s, 1.2);
    line(page, x + 14, y + 18, x + 14, y + 15, s, 1.2);
    return;
  }

  if (type === "id") {
    page.drawRectangle({ x: x + 2, y: y + 2, width: 16, height: 15, borderColor: s, borderWidth: 1.2 });
    circle(page, x + 7, y + 11, 1.6, s);
    line(page, x + 10, y + 12, x + 16, y + 12, s, 1);
    line(page, x + 5, y + 7, x + 16, y + 7, s, 1);
    return;
  }

  if (type === "clock") {
    circle(page, x + 10, y + 10, 8, undefined, s, 1.3);
    line(page, x + 10, y + 10, x + 10, y + 15, s, 1.2);
    line(page, x + 10, y + 10, x + 15, y + 10, s, 1.2);
    return;
  }

  if (type === "bus") {
    page.drawRectangle({ x: x + 3, y: y + 6, width: 14, height: 10, borderColor: s, borderWidth: 1.2 });
    line(page, x + 5, y + 12, x + 15, y + 12, s, 1);
    circle(page, x + 6, y + 5, 1.5, s);
    circle(page, x + 14, y + 5, 1.5, s);
    return;
  }

  if (type === "ticket") {
    page.drawRectangle({ x: x + 3, y: y + 5, width: 14, height: 10, borderColor: s, borderWidth: 1.2 });
    line(page, x + 8, y + 5, x + 8, y + 15, s, 1);
    return;
  }

  if (type === "person") {
    circle(page, x + 10, y + 14, 3.2, undefined, s, 1.2);
    line(page, x + 4, y + 4, x + 7, y + 10, s, 1.2);
    line(page, x + 7, y + 10, x + 13, y + 10, s, 1.2);
    line(page, x + 13, y + 10, x + 16, y + 4, s, 1.2);
    return;
  }

  if (type === "seat") {
    line(page, x + 6, y + 16, x + 6, y + 6, s, 1.3);
    line(page, x + 6, y + 10, x + 14, y + 10, s, 1.3);
    line(page, x + 14, y + 10, x + 17, y + 5, s, 1.3);
    line(page, x + 6, y + 5, x + 17, y + 5, s, 1.3);
    return;
  }

  if (type === "card") {
    page.drawRectangle({ x: x + 2, y: y + 5, width: 16, height: 11, borderColor: s, borderWidth: 1.2 });
    line(page, x + 2, y + 12, x + 18, y + 12, s, 1.2);
    return;
  }

  if (type === "receipt") {
    page.drawRectangle({ x: x + 5, y: y + 3, width: 10, height: 15, borderColor: s, borderWidth: 1.2 });
    line(page, x + 7, y + 13, x + 13, y + 13, s, 1);
    line(page, x + 7, y + 9, x + 13, y + 9, s, 1);
    line(page, x + 7, y + 6, x + 11, y + 6, s, 1);
    return;
  }

  if (type === "check") {
    circle(page, x + 10, y + 10, 8, undefined, s, 1.3);
    line(page, x + 6, y + 10, x + 9, y + 7, s, 1.3);
    line(page, x + 9, y + 7, x + 15, y + 14, s, 1.3);
    return;
  }

  circle(page, x + 10, y + 10, 8, undefined, s, 1.3);
}

function field(
  page: PDFPage,
  label: string,
  value: string,
  iconType: string,
  iconX: number,
  textX: number,
  labelY: number,
  font: PDFFont,
  bold: PDFFont,
  maxW = 120
) {
  icon(page, iconX, labelY - 16, iconType);
  drawText(page, label, textX, labelY, 8.5, font, C.muted);
  drawText(page, value, textX, labelY - 15, 9.8, bold, C.dark, maxW);
}

function sectionTitle(page: PDFPage, value: string, x: number, y: number, bold: PDFFont) {
  drawText(page, value.toUpperCase(), x, y, 9.5, bold, C.teal);
}

